/// <summary>
/// Find method 
/// </summary>
static ETGRailCarLoadingTable find(ETGRailLoadingSerialNumber          railLoadingSerialNumber,
                       boolean          _forUpdate = false,
                       ConcurrencyModel _concurrencyModel = ConcurrencyModel::Auto)
{
    ETGRailCarLoadingTable  RailCarLoadingTable;

    if (railLoadingSerialNumber)
    {
        if (_forUpdate)
        {
            RailCarLoadingTable.selectForUpdate (_forUpdate);
            if (_concurrencyModel != ConcurrencyModel::Auto)
            {
                RailCarLoadingTable.concurrencyModel(_concurrencyModel);
            }
        }
        RailCarLoadingTable.selectLocked    (_forUpdate);

        select firstonly RailCarLoadingTable
            where RailCarLoadingTable.ETGRailLoadingSerialNumber == railLoadingSerialNumber;
    }

    return RailCarLoadingTable;
}

/// <summary>
/// exist method
/// </summary>
static boolean exist(ETGRailLoadingSerialNumber          railLoadingSerialNumber)
{
    if (!railLoadingSerialNumber)
    {
        return false;
    }

    return (select firstonly RecId from ETGRailCarLoadingTable
                index hint RailCarLoadingNumber
                where ETGRailCarLoadingTable.ETGRailLoadingSerialNumber == railLoadingSerialNumber).RecId != 0;
}
